{"id":"go:hugolib/shortcode.go#prepareShortcodesForPage@536","source":"func (s *shortcodeParseInfo) prepareShortcodesForPage(po *pageOutput, isRenderString bool) (map[string]shortcodeRenderer, error) {
	rendered := make(map[string]shortcodeRenderer)

	for _, v := range s.shortcodes {
		s, err := prepareShortcode(0, v, nil, po, isRenderString)
		if err != nil {
			return nil, err
		}
		rendered[v.placeholder] = s
